--v4.24 - for any errors or question my discord: kamuworl
Moves = {
    "Anger Rush",
    "Deadly Dance",
    "Flash Skewer",
    "Meteor Crash",
    "Flash Strike"
}


Settings = {

   -- Earth world
    FarmEarth = false; --usa el pad en la tierra 
	JoinLowPopEarth = false; --para ejecutores con https 200, te une al servidor con menos gente (no recomiendo para afk)
	RejoinEarth = 75,
------------------------------------------------------
   -- Queue world
    RejoinQueue = 36,
--  para el randomMode desactiva mode2 y 3
    JoinSamePadPlrs = false; --mode2 te une al pad con menor tiempo
    PadSelector = true; --mode3 usa el pad que escojiste
    SelectPad = 7; --1 (first pad) to seven (last pad)
------------------------------------------------------
   -- Broly world
    FOV = 120; --Max 120
    RejoinBroly = 400; --si no lo matas en esos segundos te manda a queue/tierra
    BrolyDistance = 6; --tu distancia con broly
    PetTime = 1.7; --segundos para activar el assistente (B)
    ForKiDamage = true; --tu ki se pega a broly
    AntiLeech = false; --si alguien entra a tu broly te regresa a queue/tierra
   -- | Transformations
    Transformations = false; --para razas que cargan ki
    ChargeTime = 3; --tiempo de carga
    FormType = "h"; --"g" or "h"
    DroidForm = true; --(Android race only) usa corriente directa cuando tu ki llega a 70%
    UseGod = true; --usa god cuando tienes poca vida y ki
	UsePunch = false; --usa golpes normales cuando tengas poco ki (aveces da kick)
	AutoBlock = true;
   -- |
	FastGod = false;  --baja el poder para irte mas rapido a god
	MinPower = 10; --(del 5 al 100) mientras mas bajo mas vida te quitan con FastGod, sube o baja cada 5
------------------------------------------------------

   -- Others
   	ExtraTime1 = 0; --para tierra o queue
	ExtraTime2 = 0; --para broly
   -- |
    ViewStats = true; --muestra tus stats
    EnableFakeUser = false;
    FakeUser = "kamu"; --name que quieras mostrar en stats
	UseImageStats = false,
	BannerStats = "1"; --imagen que muestra las stats (from 1 to 8)
	ColorStats = {0, 0, 0}, --deshabilita UseImageStats
   -- |
    UseAnimation = false; --usa emotes
    AssetAnimId = ""; --debes poner el asset id del emote que quieras
	FPSBoost = false; --poop graphics
   -- |
    DuoMode = false; --activalo en las dos cuentas para detectar al carry
    MainAcc = "linda125xd"; --la cuenta a la que se hara tp
	AltAcc = "zomvie2x"; --la que usara el tp y dara reds (carry)
	SpamJarsOnly = false; --no ataca y solo spamea jars
------------------------------------------------------

    AutoStats = {
        Enable = false,
        Add = "Phys-Damage"; --[ "Health-Max", "Ki-Resist", "Phys-Resist", "Ki-Damage", "Phys-Damage", "Ki-Max", "Speed" ]
    };
}
]]


